import React from 'react';

const navItems = [
  { id: 'dashboard', icon: '🏠', label: 'Dashboard' },
  { id: 'disease', icon: '🔬', label: 'Disease Detection' },
  { id: 'yield', icon: '📊', label: 'Yield Prediction' },
  { id: 'irrigation', icon: '💧', label: 'Smart Irrigation' },
  { id: 'fertilizer', icon: '🧪', label: 'Fertilizer Advisor' },
];

export default function Sidebar({ activeTab, setActiveTab, sensorData }) {
  return (
    <aside style={{
      position: 'fixed', left: 0, top: 0, bottom: 0, width: 'var(--sidebar-w)',
      background: 'linear-gradient(180deg, #0F172A 0%, #0A1628 100%)',
      borderRight: '1px solid var(--border)',
      display: 'flex', flexDirection: 'column', zIndex: 100,
    }}>
      {/* Logo */}
      <div style={{ padding: '24px 20px 18px', borderBottom: '1px solid var(--border)' }}>
        <div style={{ fontSize: '30px', marginBottom: '8px' }}>🌱</div>
        <div style={{
          fontSize: '19px', fontWeight: 900, letterSpacing: '-0.5px',
          background: 'linear-gradient(135deg, #4ADE80, #22D3EE)',
          WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
        }}>AgroMind AI</div>
        <div style={{ fontSize: '10px', color: '#475569', marginTop: '3px', letterSpacing: '2px', textTransform: 'uppercase' }}>
          Smart Farming Assistant
        </div>
      </div>

      {/* Nav */}
      <nav style={{ padding: '14px 12px', flex: 1 }}>
        <div style={{ fontSize: '10px', color: '#334155', letterSpacing: '1.5px', marginBottom: '10px', paddingLeft: '8px', textTransform: 'uppercase' }}>
          Modules
        </div>
        {navItems.map(item => {
          const active = activeTab === item.id;
          return (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              style={{
                display: 'flex', alignItems: 'center', gap: '10px',
                padding: '10px 12px', borderRadius: '10px', cursor: 'pointer',
                marginBottom: '4px', width: '100%', textAlign: 'left',
                background: active ? 'linear-gradient(135deg, rgba(74,222,128,0.12), rgba(34,211,238,0.08))' : 'transparent',
                border: active ? '1px solid rgba(74,222,128,0.25)' : '1px solid transparent',
                color: active ? '#4ADE80' : '#64748B',
                fontSize: '14px', fontWeight: active ? 700 : 400,
                transition: 'all 0.2s', fontFamily: 'inherit',
              }}
            >
              <span style={{ fontSize: '17px', flexShrink: 0 }}>{item.icon}</span>
              <span>{item.label}</span>
              {active && <span style={{ marginLeft: 'auto', width: '6px', height: '6px', borderRadius: '50%', background: '#4ADE80' }} />}
            </button>
          );
        })}
      </nav>

      {/* Live sensors */}
      <div style={{ padding: '16px', borderTop: '1px solid var(--border)' }}>
        <div style={{ fontSize: '10px', color: '#334155', letterSpacing: '1.5px', marginBottom: '10px', textTransform: 'uppercase' }}>
          Live Sensors
        </div>
        <div style={{ display: 'flex', gap: '8px', marginBottom: '12px' }}>
          <div style={{ flex: 1, background: 'rgba(245,158,11,0.08)', border: '1px solid rgba(245,158,11,0.2)', borderRadius: '10px', padding: '10px', textAlign: 'center' }}>
            <div style={{ fontSize: '18px', fontWeight: 800, color: '#F59E0B' }}>{sensorData.temp}°C</div>
            <div style={{ fontSize: '10px', color: '#64748B', marginTop: '2px' }}>Temp</div>
          </div>
          <div style={{ flex: 1, background: 'rgba(59,130,246,0.08)', border: '1px solid rgba(59,130,246,0.2)', borderRadius: '10px', padding: '10px', textAlign: 'center' }}>
            <div style={{ fontSize: '18px', fontWeight: 800, color: '#3B82F6' }}>{sensorData.moisture}%</div>
            <div style={{ fontSize: '10px', color: '#64748B', marginTop: '2px' }}>Moisture</div>
          </div>
        </div>
        <div style={{
          display: 'flex', alignItems: 'center', gap: '6px',
          padding: '8px 10px', background: 'rgba(74,222,128,0.06)',
          borderRadius: '8px', border: '1px solid rgba(74,222,128,0.15)'
        }}>
          <span style={{ width: '6px', height: '6px', borderRadius: '50%', background: '#4ADE80', flexShrink: 0, animation: 'pulse 2s infinite' }} />
          <span style={{ fontSize: '11px', color: '#64748B' }}>IoT Sensors Online</span>
        </div>
      </div>
    </aside>
  );
}
